
"use client"

import { useState, useEffect, useMemo } from "react";
import dynamic from "next/dynamic";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Navigation, Loader2, MapPin, Zap, ShieldAlert, Timer, Flag } from "lucide-react";
import { useUser, useFirestore, useCollection, useMemoFirebase } from "@/firebase";
import { collection, query, orderBy } from "firebase/firestore";
import { useDriving } from "@/context/driving-context";
import { calculateRoute, RouteData } from "@/services/navigation/routeService";
import { useToast } from "@/hooks/use-toast";

const DriveRankMap = dynamic(() => import("@/components/map/DriveRankMap"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-zinc-950 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-accent" /></div>
});

const CITIES = [
  { name: "Prishtinë", lat: 42.6629, lng: 21.1655 },
  { name: "Prizren", lat: 42.2139, lng: 20.7410 },
  { name: "Pejë", lat: 42.6593, lng: 20.2883 },
  { name: "Ferizaj", lat: 42.3705, lng: 21.1555 },
  { name: "Gjakovë", lat: 42.3803, lng: 20.4358 },
  { name: "Gjilan", lat: 42.4635, lng: 21.4678 },
  { name: "Mitrovicë", lat: 42.8914, lng: 20.8660 },
];

export default function NavigationPage() {
  const { currentCoords, speed } = useDriving();
  const db = useFirestore();
  const { toast } = useToast();
  
  const [destination, setDestination] = useState<{name: string, lat: number, lng: number} | null>(null);
  const [routeData, setRouteData] = useState<RouteData | null>(null);
  const [isLoadingRoute, setIsLoadingRoute] = useState(false);

  const radarQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(collection(db, "radar_reports"), orderBy("createdAt", "desc"));
  }, [db]);
  const { data: alerts } = useCollection(radarQuery);

  const handleCalculateRoute = async (city: any) => {
    if (!currentCoords) {
      toast({ variant: "destructive", title: "LOKACIONI 📍", description: "Lejoni GPS-in për navigim." });
      return;
    }
    setDestination(city);
    setIsLoadingRoute(true);
    
    const result = await calculateRoute(currentCoords, { lat: city.lat, lng: city.lng });
    if (result) {
      setRouteData(result);
      toast({ title: "RRUGA U GJET 🏁", description: `Distanca: ${(result.distance / 1000).toFixed(1)} km` });
    } else {
      toast({ variant: "destructive", title: "GABIM ❌", description: "Nuk u llogarit rruga." });
    }
    setIsLoadingRoute(false);
  };

  const alertsOnRoute = useMemo(() => {
    if (!routeData || !alerts) return [];
    // Thjeshtëzim: Filtrojmë radarët që janë afër destinacionit ose rrugës (brenda rrezes 1km)
    return alerts.filter(alert => {
      return routeData.coordinates.some(coord => {
        const dist = Math.sqrt(Math.pow(alert.lat - coord[0], 2) + Math.pow(alert.lng - coord[1], 2));
        return dist < 0.005; // ~500m
      });
    });
  }, [routeData, alerts]);

  return (
    <div className="flex flex-col h-screen bg-black relative overflow-hidden">
      <div className="absolute inset-0 z-0">
        <DriveRankMap 
          userLocation={currentCoords} 
          route={routeData?.coordinates || null} 
          alerts={alerts || []}
          destination={destination}
        />
      </div>

      {/* Top Search Card */}
      <div className="absolute top-6 left-4 right-4 z-20">
        <Card className="glass-card p-4 rounded-[2rem] border-white/5 shadow-2xl space-y-3">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-accent/20 rounded-xl flex items-center justify-center">
              <Navigation className="w-5 h-5 text-accent" />
            </div>
            <div className="flex-1">
              <p className="text-[8px] font-black text-muted-foreground uppercase tracking-widest">DESTINACIONI</p>
              <Select onValueChange={(val) => handleCalculateRoute(CITIES.find(c => c.name === val))}>
                <SelectTrigger className="h-8 border-none bg-transparent p-0 font-black italic uppercase text-sm text-white focus:ring-0">
                  <SelectValue placeholder="Zgjidh Qytetin..." />
                </SelectTrigger>
                <SelectContent className="glass border-white/10 rounded-2xl">
                  {CITIES.map(city => (
                    <SelectItem key={city.name} value={city.name} className="font-bold uppercase italic text-xs">{city.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            {isLoadingRoute && <Loader2 className="w-5 h-5 animate-spin text-accent" />}
          </div>
        </Card>
      </div>

      {/* Navigation Stats & Alerts */}
      {routeData && (
        <div className="absolute bottom-28 left-4 right-4 z-20 space-y-3">
          {alertsOnRoute.length > 0 && (
            <Badge className="w-full bg-red-600/90 backdrop-blur-xl text-white font-black uppercase italic py-3 rounded-2xl border border-red-500/50 shadow-2xl animate-pulse-red flex items-center justify-center gap-2">
              <ShieldAlert className="w-4 h-4" />
              KUJDES: {alertsOnRoute.length} RADARË PËRPARA! 📡
            </Badge>
          )}

          <Card className="glass-card p-5 rounded-[2.5rem] border-accent/20 shadow-2xl sporty-gradient">
            <div className="grid grid-cols-3 gap-4">
              <div className="flex flex-col items-center">
                <Timer className="w-4 h-4 text-muted-foreground mb-1" />
                <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">KOHA</span>
                <span className="text-sm font-black text-white italic">{Math.round(routeData.duration / 60)} MIN</span>
              </div>
              <div className="flex flex-col items-center border-x border-white/5">
                <Flag className="w-4 h-4 text-accent mb-1" />
                <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">DISTANCA</span>
                <span className="text-sm font-black text-accent italic">{(routeData.distance / 1000).toFixed(1)} KM</span>
              </div>
              <div className="flex flex-col items-center">
                <Zap className="w-4 h-4 text-red-500 mb-1" />
                <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">LIVE</span>
                <span className="text-sm font-black text-red-500 italic">{speed} KM/H</span>
              </div>
            </div>
          </Card>
        </div>
      )}

      {/* Speed HUD Floating */}
      {!routeData && (
        <div className="absolute bottom-28 right-6 z-20">
          <div className="glass-card border-accent/20 w-16 h-16 rounded-2xl flex flex-col items-center justify-center shadow-2xl bg-zinc-950/80">
            <span className="text-xl font-black text-white leading-none">{speed}</span>
            <span className="text-[6px] font-black text-muted-foreground uppercase tracking-widest">KM/H</span>
          </div>
        </div>
      )}

      <BottomNav />
    </div>
  );
}
